def solve(nums: Array[Long]): Long = {
  val n = nums.length
  if (n == 0) return 0L
  if (n == 1) return 0L

  val maxNum = 1000000
  val spf = Array.fill(maxNum + 1)(0)
  for (i <- 2 to maxNum) {
    if (spf(i) == 0) {
      spf(i) = i
      for (j <- i * 2 to maxNum by i) {
        if (spf(j) == 0) spf(j) = i
      }
    }
  }

  def getPrimes(x: Int): Set[Int] = {
    if (x == 1) return Set()
    val primes = scala.collection.mutable.Set[Int]()
    var n = x
    while (n > 1) {
      val p = spf(n)
      primes += p
      while (n % p == 0) n /= p
    }
    primes
  }

  val primeToIndices = scala.collection.mutable.HashMap[Int, List[Int]]()
  for (i <- 0 until n) {
    val x = nums(i).toInt
    if (x == 1) continue
    val primes = getPrimes(x)
    for (p <- primes) {
      primeToIndices(p) = primeToIndices.getOrElse(p, List[Int]) :+ i
    }
  }

  val visited = scala.collection.mutable.HashSet[Int]()
  val queue = scala.collection.mutable.Queue[(Int, Int)]()
  queue += (0, 0)
  visited += 0

  while (queue.nonEmpty) {
    val (current, steps) = queue.dequeue()
    if (current == n - 1) return steps.toLong
    val nextIndices = List(current - 1, current + 1)
    for (next <- nextIndices) {
      if (next >= 0 && next < n && !visited.contains(next)) {
        visited += next
        queue += (next, steps + 1)
      }
    }
    val x = nums(current).toInt
    if (x != 1 && spf(x) == x) {
      val p = x
      val indices = primeToIndices.get(p).getOrElse(List())
      for (j <- indices) {
        if (j != current && !visited.contains(j)) {
          visited += j
          queue += (j, steps + 1)
        }
      }
    }
  }

  -1L
}
